import groovy.json.*

def sourceProps = testRunner.testCase.testSuite.project
                    .testSuites['GSBet _settlement']
                    .testCases['TerminalCreation']
                    .testSteps['Properties']

def terminalIDs = sourceProps.getPropertyValue('Result')
log.info "Raw Result from TerminalCreation: ${terminalIDs}"

if (terminalIDs?.trim()) {
    def cleanList = terminalIDs.substring(1, terminalIDs.length() - 1).tokenize(', ')
    log.info "Parsed List: ${cleanList}"

    def i = testRunner.testCase.testSteps['Properties'].getPropertyValue("i") as Integer ?: 0

    if (i < cleanList.size()) {
        def terminalId = cleanList[i].trim()
        log.info "✅ Using Terminal [${i}] = ${terminalId}"

        testRunner.testCase.testSteps['Properties'].setPropertyValue("TerminalWalletId", terminalId)
    } else {
        log.error "Index ${i} out of range. Total terminals: ${cleanList.size()}"
    }
} else {
    log.error "❌ 'Result' property is still empty in TerminalCreation!"
}

