import groovy.xml.*

def response = context.expand('${CheckTicket#ResponseAsXml#Results//TICKET.STATUS}')

if(response == 'Rejected'){
		log.info 'Ticket was rejected. Going back to generator...'
		testRunner.gotoStepByName("DatetimeGen")
	} else {
		if (response == 'Created'){
			log.info 'Ticket is created.'
			testRunner.gotoStepByName("DatetimeGen2")
		}
		if (response == 'AuthorizationPending'){
			log.info 'Authorization is pending...'
			testRunner.gotoStepByName("AuthorizeTicket")
		}
		if(response == 'NotProcessed'){
			log.info 'Ticket is being processed...'
			testRunner.gotoStepByName("DatetimeGen2")
		}
	}

import groovy.time.TimeCategory
TimeZone.setDefault(TimeZone.getTimeZone('UTC'))

use (TimeCategory) {
	def now = new Date()
	//def fromDate = now - 30.minutes
	def fromDate = now
	def toDate = now + 1.hour
	//log.info fromDate.format("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'")
	//log.info toDate.format("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'")
	testRunner.testCase.testSteps["Datetime2"].setPropertyValue( "fromDate", fromDate.format("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'") )
	testRunner.testCase.testSteps["Datetime2"].setPropertyValue( "toDate", toDate.format("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'") )
	testRunner.testCase.testSteps["Datetime2"].setPropertyValue( "now", now.format("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'") )
	return fromDate.format("yyyy-MM-dd'T'HH:mm:ss")
}

