import groovy.time.TimeCategory
TimeZone.setDefault(TimeZone.getTimeZone('UTC'))

use (TimeCategory) {
	def now = new Date()
	def fromDate = now - 30.minutes
	def toDate = now + 1.hour
	log.info fromDate.format("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'")
	log.info toDate.format("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'")
	testRunner.testCase.testSteps["Datetime3"].setPropertyValue( "fromDate", fromDate.format("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'") )
	testRunner.testCase.testSteps["Datetime3"].setPropertyValue( "toDate", toDate.format("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'") )
	testRunner.testCase.testSteps["Datetime3"].setPropertyValue( "now", now.format("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'") )
	return fromDate.format("yyyy-MM-dd'T'HH:mm:ss")
}

