import groovy.json.*
def payin = context.expand('${DB_walletState#ResponseAsXml#//PAYIN}') as Double
def payout = context.expand('${DB_walletState#ResponseAsXml#//PAYOUT}') as Double
//def wintax = context.expand('${DB_walletState#ResponseAsXml#//WINTAX}') as Double
def servicecharge = context.expand('${DB_walletState#ResponseAsXml#//SERVICECHARGE}') as Double

def final_amount = payin - payout - servicecharge
def amount =  final_amount.round(0)
//Thread.sleep(2000);
//log.info amount.getClass()
log.info amount
if (amount < (0 as Double)){
	testRunner.testCase.testSteps['Properties'].setPropertyValue("BetAmount",amount as String)
	testRunner.testCase.testSteps['Properties'].setPropertyValue("Status",'Lost')
	testRunner.gotoStepByName('BetAmount')
}else{
	testRunner.testCase.testSteps['Properties'].setPropertyValue("Status",'Win')
	testRunner.gotoStepByName('DB_submanagerID')
}

